class Solution:
    def xorAllNums(self, nums1, nums2):
        result = 0
        if len(nums2) % 2 == 1:
            for x in nums1:
                result ^= x
        if len(nums1) % 2 == 1:
            for y in nums2:
                result ^= y
        return result

